sys_ui_page.client_script:
initPage();

// Use this function to remove the disabled attribute from the submit button
function enableSubmitButton() {
	gel('submit').disabled = gel('newRejectionReason').value.length == 0;
}

// Use this function to initialize variables at page load
function initPage() {
	gel('newRejectionReason').value = gel('newRejectionReason').value.trim();
	var reasonLength = gel('newRejectionReason').value.length;

	if (reasonLength == 0) {
		gel('submit').disabled = true;
	} else {
		gel('submit').disabled = false;
	}
}

// dialog_button id="cancel" was clicked, user does not want to delete the task
function onCancel() {
    // below will auto close popup
    GlideDialogWindow.get().destroy();
    return false;
}

// dialog_button id="submit" was clicked, user confirms wanting to delete the task
function onSubmit() {
    return true;
}

sys_ui_page.processing_script:
reject_approval();

function reject_approval() {
    var grTasksReject = new GlideRecord("x_153465_discovert_route_task_instance");
    grTasksReject.addQuery('sys_id', sysid);
    grTasksReject.query();

    if (grTasksReject.next()) {
		grTasksReject.comments_dt = newRejectionReason;
		new Task_uiAction().uiAction_UpdateTaskAndResponseLog("Rejected", 'reject', grTasksReject);
    }

    response.sendRedirect("/x_153465_discovert_route_task_instance.do?sys_id=" + sysid);
}
